function solve(code: string[], businessLine: string[], isActive: boolean[]): string[] {
    const allowedBusinessLines = ["electronics", "grocery", "pharmacy", "restaurant"];
    const codeRegex = /^[a-zA-Z0-9_]+$/;
    const validCoupons: { code: string; businessLine: string }[] = [];

    for (let i = 0; i < code.length; i++) {
        const c = code[i];
        const bl = businessLine[i];
        const active = isActive[i];

        if (c !== "" && codeRegex.test(c) && allowedBusinessLines.includes(bl) && active) {
            validCoupons.push({ code: c, businessLine: bl });
        }
    }

    validCoupons.sort((a, b) => {
        const aBL = a.businessLine;
        const bBL = b.businessLine;
        const aIdx = allowedBusinessLines.indexOf(aBL);
        const bIdx = allowedBusinessLines.indexOf(bBL);
        if (aIdx !== bIdx) {
            return aIdx - bIdx;
        } else {
            return a.code.localeCompare(b.code);
        }
    });

    return validCoupons.map(c => c.code);
}

