fun solve(code: Array<String>, businessLine: Array<String>, isActive: Array<Boolean>): Array<String> {
    val allowedBusinessLines = listOf("electronics", "grocery", "pharmacy", "restaurant")
    val valid = code.indices.filter { i ->
        val c = code[i]
        val bl = businessLine[i]
        val active = isActive[i]
        c.isNotEmpty() && Regex("^[a-zA-Z0-9_]+$").matches(c) && allowedBusinessLines.contains(bl) && active
    }.map { i -> code[i] to businessLine[i] }

    val sorted = valid.sortedWith(compareBy<Pair<String, String>> { pair ->
        allowedBusinessLines.indexOf(pair.second)
    }.thenCompareBy { pair -> pair.first })

    return sorted.map { it.first }.toTypedArray()
}
```

